def search_in_hadith(snippet_norm):
    matches = []
    for h in hadith:
        for field in ('hadithTxt','Matn'):
            txt = h.get(field) or ""
            if not txt: continue
            if snippet_norm in normalize(txt):
                matches.append((h['hadithID'], field, txt[:200]))
                break
    return matches

